import React from "react";

const experiences = [
  {
    id: 1,
    title: "Skydiving Adventure",
    description: "Experience the thrill of freefall from 15,000 feet!",
    image:
      "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?fit=crop&w=800&q=80",
  },
  {
    id: 2,
    title: "Mountain Hiking",
    description: "Explore breathtaking mountains and nature trails.",
    image:
      "https://images.unsplash.com/photo-1501785888041-af3ef285b470?fit=crop&w=800&q=80",
  },
  {
    id: 3,
    title: "Scuba Diving",
    description: "Dive into the ocean and discover marine life.",
    image:
      "https://images.unsplash.com/photo-1470770903676-69b98201ea1c?fit=crop&w=800&q=80",
  },
];

function Experience() {
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-100 via-pink-100 to-purple-100 py-12 flex flex-col items-center">
      {/* Page Title */}
      <h1 className="text-4xl sm:text-5xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-blue-700 to-pink-600 mb-10 text-center">
        Unforgettable Experiences 🌍
      </h1>

      {/* Experience Cards - Centered */}
      <div className="flex flex-col items-center space-y-10 w-full max-w-3xl px-4">
        {experiences.map((exp) => (
          <div
            key={exp.id}
            className="bg-white rounded-2xl shadow-xl hover:shadow-2xl transition-all duration-300 overflow-hidden transform hover:-translate-y-2 w-full"
          >
            <img
              src={exp.image}
              alt={exp.title}
              className="w-full h-72 object-cover"
            />
            <div className="p-6 text-center">
              <h3 className="text-2xl font-semibold text-gray-800 mb-2">
                {exp.title}
              </h3>
              <p className="text-gray-600 text-sm mb-4 leading-relaxed">
                {exp.description}
              </p>
              <button className="bg-gradient-to-r from-blue-600 to-pink-500 text-white font-medium px-6 py-2 rounded-full shadow-md hover:shadow-lg transition-all duration-300">
                Learn More
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Experience;
